fn solve(prices: Vec<i64>, strategy: Vec<i64>, k: i64) -> i64 {
    let n = prices.len();
    let original_profit: i64 = strategy.iter().zip(prices.iter()).map(|(&s, &p)| s * p).sum();
    let mut max_profit = original_profit;

    let half_k = (k / 2) as usize;
    let mut prefix_diff = vec![0; n + 1];

    for i in 0..n {
        let current_strategy = strategy[i];
        let new_strategy = if i < half_k { 0 } else { 1 };
        let diff = (new_strategy - current_strategy) * prices[i];
        prefix_diff[i + 1] = prefix_diff[i] + diff;
    }

    let mut max_diff = 0;
    let mut current_window_sum = 0;
    let k_usize = k as usize;

    for i in 1..=n {
        current_window_sum += prefix_diff[i] - prefix_diff[i - 1];
        if i > k_usize {
            current_window_sum -= prefix_diff[i - k_usize] - prefix_diff[i - k_usize - 1];
        }
        if i >= k_usize {
            if current_window_sum > max_diff {
                max_diff = current_window_sum;
            }
        }
    }

    max_profit = original_profit + max_diff;
    max_profit
}
